export const DISPLAY_NAME_MAX_LENGTH = 48;

export function isValidDisplayName(value: string): boolean {
  const normalized = value.trim();

  return (
    normalized.length >= 1 &&
    normalized.length <= DISPLAY_NAME_MAX_LENGTH &&
    /^[\p{L}\p{M} .'-]+$/u.test(normalized)
  );
}

// Imported by both the browser form and profile API.
export function validateProfileUpdate(input: ProfileUpdateInput) {
  if (!isValidDisplayName(input.displayName)) {
    return { ok: false, reason: "invalid-display-name" };
  }

  return { ok: true };
}
